# ============================================================
# Encryption utilities for sensitive data
# ============================================================

class DataProtector:
    """Handles encryption/hashing of sensitive data before storing in Redis."""

    def __init__(self, encryption_key: str):
        if not encryption_key:
            raise ValueError("ENCRYPTION_KEY environment variable must be set for data protection")
        self._key = encryption_key.encode('utf-8')

    def hash_token(self, token: str) -> str:
        """Create HMAC hash of a token for secure storage/lookup."""
        return hmac.new(self._key, token.encode('utf-8'), hashlib.sha256).hexdigest()

    def hash_api_key(self, api_key: str) -> str:
        """Create HMAC hash of an API key for secure storage/lookup."""
        return hmac.new(self._key, api_key.encode('utf-8'), hashlib.sha256).hexdigest()

    @staticmethod
    def generate_session_token() -> str:
        """Generate a cryptographically secure session token."""
        return secrets.token_urlsafe(48)

    @staticmethod
    def generate_api_key() -> str:
        """Generate a cryptographically secure API key."""
        prefix = "sk_live_"
        return prefix + secrets.token_urlsafe(40)


# ============================================================
# Redis Cluster Connection Manager
# ============================================================

class RedisClusterManager:
    """Manages connections to Redis cluster with retry logic and health checks."""

    def __init__(self, config: Config):
        self._config = config
        self._cluster: Optional[RedisCluster] = None
        self._connect()

    def _parse_cluster_nodes(self):
        """Parse cluster node addresses from config string."""
        nodes = []
        for node_str in self._config.REDIS_CLUSTER_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def _connect(self):
        """Establish connection to Redis cluster."""
        startup_nodes = self._parse_cluster_nodes()

        connection_kwargs = {
            "socket_timeout": self._config.REDIS_SOCKET_TIMEOUT,
            "socket_connect_timeout": self._config.REDIS_SOCKET_CONNECT_TIMEOUT,
            "retry_on_timeout": self._config.REDIS_RETRY_ON_TIMEOUT,
            "max_connections": self._config.REDIS_MAX_CONNECTIONS,
        }

        if self._config.REDIS_PASSWORD:
            connection_kwargs["password"] = self._config.REDIS_PASSWORD

        if self._config.REDIS_SSL:
            connection_kwargs["ssl"] = True
            connection_kwargs["ssl_ca_certs"] = self._config.REDIS_SSL_CA_CERTS
            connection_kwargs["ssl_certfile"] = self._config.REDIS_SSL_CERTFILE
            connection_kwargs["ssl_keyfile"] = self._config.REDIS_SSL_KEYFILE
            if self._config.REDIS_SSL_CERT_REQS == "required":
                connection_kwargs["ssl_cert_reqs"] = "required"
            else:
                connection_kwargs["ssl_cert_reqs"] = "none"

        max_retries = 3
        for attempt in range(max_retries):
            try:
                self._cluster = RedisCluster(
                    startup_nodes=startup_nodes,
                    decode_responses=True,
                    skip_full_coverage_check=True,
                    **connection_kwargs
                )
                # Test connection
                self._cluster.ping()
                logger.info("Successfully connected to Redis cluster")
                return
            except (ConnectionError, TimeoutError, RedisError) as e:
                logger.warning(
                    f"Redis connection attempt {attempt + 1}/{max_retries} failed: {e}"
                )
                if attempt == max_retries - 1:
                    logger.error("Failed to connect to Redis cluster after all retries")
                    raise
                time.sleep(2 ** attempt)  # Exponential backoff

    @property
    def client(self) -> RedisCluster:
        """Get the Redis cluster client, reconnecting if necessary."""
        if self._cluster is None:
            self._connect()
        try:
            self._cluster.ping()
        except (ConnectionError, TimeoutError, RedisError):
            logger.warning("Redis connection lost, attempting reconnection")
            self._connect()
        return self._cluster

    def health_check(self) -> Dict[str, Any]:
        """Perform health check on Redis cluster."""
        try:
            start = time.time()
            self.client.ping()
            latency_ms = (time.time() - start) * 1000

            cluster_info = self.client.cluster_info()
            return {
                "status": "healthy",
                "latency_ms": round(latency_ms, 2),
                "cluster_state": cluster_info.get("cluster_state", "unknown"),
                "cluster_slots_assigned": cluster_info.get("cluster_slots_assigned", 0),
                "cluster_known_nodes": cluster_info.get("cluster_known_nodes", 0),
            }
        except Exception as e:
            return {
                "status": "unhealthy",
                "error": str(e),
            }

    def close(self):
        """Close the Redis cluster connection."""
        if self._cluster:
            self._cluster.close()
            self._cluster = None
            logger.info("Redis cluster connection closed")


