class DistributedCacheService:
    """
    High-level caching service for sensitive user data.
    
    Key design decisions:
    - Session tokens and API keys are stored as HMAC hashes (not plaintext)
    - All keys use namespaced prefixes to avoid collisions
    - TTL is enforced on all sensitive data
    - Atomic operations used where possible for consistency
    """

    # Key prefixes (namespaced for multi-service environments)
    PREFIX_SESSION = "auth:session:"
    PREFIX_API_KEY = "auth:apikey:"
    PREFIX_REFRESH = "auth:refresh:"
    PREFIX_USER_CACHE = "cache:user:"
    PREFIX_RATE_LIMIT = "ratelimit:"
    PREFIX_REVOKED = "auth:revoked:"

    def __init__(self, redis_manager: RedisClusterManager, protector: DataProtector, config: Config):
        self._redis = redis_manager
        self._protector = protector
        self._config = config

    # ---------- Session Token Management ----------

    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> str:
        """
        Create a new session token for a user.
        Returns the raw token (only time it's available in plaintext).
        Stores HMAC hash in Redis.
        """
        raw_token = self._protector.generate_session_token()
        token_hash = self._protector.hash_token(raw_token)
        key = f"{self.PREFIX_SESSION}{token_hash}"

        session_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "ip_address": metadata.get("ip_address", "") if metadata else "",
            "user_agent": metadata.get("user_agent", "") if metadata else "",
        }

        try:
            pipeline = self._redis.client.pipeline()
            pipeline.hset(key, mapping=session_data)
            pipeline.expire(key, self._config.SESSION_TOKEN_TTL)
            pipeline.execute()

            logger.info(f"Session created for user {user_id}")
            return raw_token
        except RedisError as e:
            logger.error(f"Failed to create session for user {user_id}: {e}")
            raise

    def validate_session(self, raw_token: str) -> Optional[Dict[str, str]]:
        """
        Validate a session token and return session data if valid.
        Checks against revocation list.
        """
        token_hash = self._protector.hash_token(raw_token)

        # Check if token is revoked
        revoked_key = f"{self.PREFIX_REVOKED}{token_hash}"
        if self._redis.client.exists(revoked_key):
            logger.warning(f"Attempt to use revoked session token")
            return None

        key = f"{self.PREFIX_SESSION}{token_hash}"
        try:
            session_data = self._redis.client.hgetall(key)
            if not session_data:
                return None
            return session_data
        except RedisError as e:
            logger.error(f"Failed to validate session: {e}")
            raise

    def revoke_session(self, raw_token: str) -> bool:
        """Revoke a session token."""
        token_hash = self._protector.hash_token(raw_token)
        session_key = f"{self.PREFIX_SESSION}{token_hash}"
        revoked_key = f"{self.PREFIX_REVOKED}{token_hash}"

        try:
            pipeline = self._redis.client.pipeline()
            # Mark as revoked (keep for a while to prevent reuse)
            pipeline.set(revoked_key, "1", ex=self._config.SESSION_TOKEN_TTL)
            # Delete the session
            pipeline.delete(session_key)
            results = pipeline.execute()

            logger.info(f"Session revoked")
            return results[1] > 0  # True if session existed and was deleted
        except RedisError as e:
            logger.error(f"Failed to revoke session: {e}")
            raise

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """
        Revoke all sessions for a user.
        Note: This requires scanning, which is expensive. In production,
        maintain a user->sessions index.
        """
        count = 0
        try:
            cursor = 0
            while True:
                cursor, keys = self._redis.client.scan(
                    cursor=cursor,
                    match=f"{self.PREFIX_SESSION}*",
                    count=100
                )
                for key in keys:
                    session_data = self._redis.client.hgetall(key)
                    if session_data.get("user_id") == user_id:
                        token_hash = key.replace(self.PREFIX_SESSION, "")
                        revoked_key = f"{self.PREFIX_REVOKED}{token_hash}"
                        pipeline = self._redis.client.pipeline()
                        pipeline.set(revoked_key, "1", ex=self._config.SESSION_TOKEN_TTL)
                        pipeline.delete(key)
                        pipeline.execute()
                        count += 1

                if cursor == 0:
                    break

            logger.info(f"Revoked {count} sessions for user {user_id}")
            return count
        except RedisError as e:
            logger.error(f"Failed to revoke all sessions for user {user_id}: {e}")
            raise

    # ---------- API Key Management ----------

    def store_api_key(self, user_id: str, permissions: Optional[list] = None, description: str = "") -> str:
        """
        Generate and store a new API key for a user.
        Returns the raw API key (only time it's available in plaintext).
        """
        raw_api_key = self._protector.generate_api_key()
        key_hash = self._protector.hash_api_key(raw_api_key)
        key = f"{self.PREFIX_API_KEY}{key_hash}"

        api_key_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "description": description,
            "permissions": json.dumps(permissions or ["read"]),
            "last_used": "",
            "usage_count": "0",
        }

        try:
            pipeline = self._redis.client.pipeline()
            pipeline.hset(key, mapping=api_key_data)
            pipeline.expire(key, self._config.API_KEY_TTL)
            pipeline.execute()

            logger.info(f"API key created for user {user_id}: {description}")
            return raw_api_key
        except RedisError as e:
            logger.error(f"Failed to store API key for user {user_id}: {e}")
            raise

    def validate_api_key(self, raw_api_key: str) -> Optional[Dict[str, Any]]:
        """
        Validate an API key and return associated data.
        Also updates last_used timestamp and usage count.
        """
        key_hash = self._protector.hash_api_key(raw_api_key)

        # Check revocation
        revoked_key = f"{self.PREFIX_REVOKED}{key_hash}"
        if self._redis.client.exists(revoked_key):
            logger.warning("Attempt to use revoked API key")
            return None

        key = f"{self.PREFIX_API_KEY}{key_hash}"
        try:
            api_key_data = self._redis.client.hgetall(key)
            if not api_key_data:
                return None

            # Update usage metadata atomically
            pipeline = self._redis.client.pipeline()
            pipeline.hset(key, "last_used", datetime.utcnow().isoformat())
            pipeline.hincrby(key, "usage_count", 1)
            pipeline.execute()

            # Parse permissions back to list
            api_key_data["permissions"] = json.loads(api_key_data.get("permissions", "[]"))
            return api_key_data
        except RedisError as e:
            logger.error(f"Failed to validate API key: {e}")
            raise

    def revoke_api_key(self, raw_api_key: str) -> bool:
        """Revoke an API key."""
        key_hash = self._protector.hash_api_key(raw_api_key)
        api_key_redis_key = f"{self.PREFIX_API_KEY}{key_hash}"
        revoked_key = f"{self.PREFIX_REVOKED}{key_hash}"

        try:
            pipeline = self._redis.client.pipeline()
            pipeline.set(revoked_key, "1", ex=self._config.API_KEY_TTL)
            pipeline.delete(api_key_redis_key)
            results = pipeline.execute()
            logger.info("API key revoked")
            return results[1] > 0
        except RedisError as e:
            logger.error(f"Failed to revoke API key: {e}")
            raise

    # ---------- Refresh Token Management ----------

    def store_refresh_token(self, user_id: str, session_token_hash: str) -> str:
        """Store a refresh token linked to a session."""
        raw_refresh_token = secrets.token_urlsafe(64)
        token_hash = self._protector.hash_token(raw_refresh_token)
        key = f"{self.PREFIX_REFRESH}{token_hash}"

        refresh_data = {
            "user_id": user_id,
            "session_token_hash": session_token_hash,
            "created_at": datetime.utcnow().isoformat(),
            "used": "false",
        }

        try:
            pipeline = self._redis.client.pipeline()
            pipeline.hset(key, mapping=refresh_data)
            pipeline.expire(key, self._config.REFRESH_TOKEN_TTL)
            pipeline.execute()

            logger.info(f"Refresh token created for user {user_id}")
            return raw_refresh_token
        except RedisError as e:
            logger.error(f"Failed to store refresh token: {e}")
            raise

    def use_refresh_token(self, raw_refresh_token: str) -> Optional[Dict[str, str]]:
        """
        Use a refresh token (one-time use).
        Returns token data if valid, None otherwise.
        Implements token rotation: old token is invalidated.
        """
        token_hash = self._protector.hash_token(raw_refresh_token)
        key = f"{self.PREFIX_REFRESH}{token_hash}"

        try:
            # Use WATCH for optimistic locking
            with self._redis.client.pipeline() as pipe:
                refresh_data = self._redis.client.hgetall(key)
                if not refresh_data:
                    return None

                if refresh_data.get("used") == "true":
                    # Token reuse detected - possible token theft
                    logger.critical(
                        f"Refresh token reuse detected for user {refresh_data.get('user_id')}! "
                        "Possible token theft."
                    )
                    # Revoke all associated sessions
                    self.revoke_all_user_sessions(refresh_data.get("user_id", ""))
                    return None

                # Mark as used and delete
                pipe.hset(key, "used", "true")
                pipe.expire(key, 60)  # Keep briefly to detect reuse
                pipe.execute()

                return refresh_data
        except RedisError as e:
            logger.error(f"Failed to use refresh token: {e}")
            raise

    # ---------- User Data Cache ----------

    def cache_user_data(self, user_id: str, user_data: Dict[str, Any]) -> bool:
        """
        Cache non-sensitive user data (profile info, preferences).
        Sensitive fields are stripped before caching.
        """
        # Strip sensitive fields before caching
        sensitive_fields = {"password", "password_hash", "ssn", "credit_card", "secret"}
        safe_data = {k: v for k, v in user_data.items() if k.lower() not in sensitive_fields}

        key = f"{self.PREFIX_USER_CACHE}{user_id}"
        try:
            self._redis.client.set(
                key,
                json.dumps(safe_data),
                ex=self._config.USER_CACHE_TTL
            )
            return True
        except RedisError as e:
            logger.error(f"Failed to cache user data for {user_id}: {e}")
            return False

    def get_cached_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        """Retrieve cached user data."""
        key = f"{self.PREFIX_USER_CACHE}{user_id}"
        try:
            data = self._redis.client.get(key)
            if data:
                return json.loads(data)
            return None
        except RedisError as e:
            logger.error(f"Failed to get cached user data for {user_id}: {e}")
            return None

    def invalidate_user_cache(self, user_id: str) -> bool:
        """Invalidate cached user data."""
        key = f"{self.PREFIX_USER_CACHE}{user_id}"
        try:
            self._redis.client.delete(key)
            return True
        except RedisError as e:
            logger.error(f"Failed to invalidate user cache for {user_id}: {e}")
            return False

    # ---------- Rate Limiting ----------

    def check_rate_limit(self, identifier: str, max_requests: Optional[int] = None) -> Dict[str, Any]:
        """
        Sliding window rate limiter using Redis sorted sets.
        Returns rate limit status.
        """
        max_req = max_requests or self._config.RATE_LIMIT_MAX_REQUESTS
        window = self._config.RATE_LIMIT_WINDOW_TTL
        key = f"{self.PREFIX_RATE_LIMIT}{identifier}"
        now = time.time()
        window_start = now - window

        try:
            pipeline = self._redis.client.pipeline()
            # Remove expired entries
            pipeline.zremrangebyscore(key, 0, window_start)
            # Add current request
            pipeline.zadd(key, {f"{now}-{secrets.token_hex(4)}": now})
            # Count requests in window
            pipeline.zcard(key)
            # Set TTL on the key
            pipeline.expire(key, window)
            results = pipeline.execute()

            current_count = results[2]
            allowed = current_count <= max_req

            return {
                "allowed": allowed,
                "current_count": current_count,
                "max_requests": max_req,
                "window_seconds": window,
                "remaining": max(0, max_req - current_count),
                "retry_after": window if not allowed else 0,
            }
        except RedisError as e:
            logger.error(f"Rate limit check failed for {identifier}: {e}")
            # Fail open - allow request if Redis is down
            return {
                "allowed": True,
                "current_count": 0,
                "max_requests": max_req,
                "window_seconds": window,
                "remaining": max_req,
                "retry_after": 0,
                "error": "rate_limit_unavailable",
            }


