app = Flask(__name__)

# Initialize services
config = Config()

# Validate required configuration
if not config.ENCRYPTION_KEY:
    logger.critical("ENCRYPTION_KEY environment variable is required")
    raise SystemExit("ENCRYPTION_KEY must be set")

if not config.API_SECRET_KEY:
    logger.critical("API_SECRET_KEY environment variable is required")
    raise SystemExit("API_SECRET_KEY must be set")

protector = DataProtector(config.ENCRYPTION_KEY)
redis_manager = RedisClusterManager(config)
cache_service = DistributedCacheService(redis_manager, protector, config)


# ---------- Middleware ----------

def require_service_auth(f):
    """Authenticate inter-service communication via shared secret."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("X-Service-Key", "")
        if not auth_header:
            return jsonify({"error": "Missing service authentication"}), 401

        if not hmac.compare_digest(auth_header, config.API_SECRET_KEY):
            return jsonify({"error": "Invalid service authentication"}), 403

        return f(*args, **kwargs)
    return decorated


def rate_limit(f):
    """Apply rate limiting based on client IP."""
    @wraps(f)
    def decorated(*args, **kwargs):
        client_ip = request.headers.get("X-Forwarded-For", request.remote_addr)
        result = cache_service.check_rate_limit(f"ip:{client_ip}")

        if not result["allowed"]:
            response = jsonify({
                "error": "Rate limit exceeded",
                "retry_after": result["retry_after"],
            })
            response.headers["Retry-After"] = str(result["retry_after"])
            response.headers["X-RateLimit-Limit"] = str(result["max_requests"])
            response.headers["X-RateLimit-Remaining"] = "0"
            return response, 429

        g.rate_limit_remaining = result["remaining"]
        return f(*args, **kwargs)
    return decorated


@app.after_request
def add_rate_limit_headers(response):
    """Add rate limit headers to all responses."""
    if hasattr(g, "rate_limit_remaining"):
        response.headers["X-RateLimit-Remaining"] = str(g.rate_limit_remaining)
    return response


# ---------- Health Check ----------

@app.route("/health", methods=["GET"])
def health_check():
    redis_health = redis_manager.health_check()
    overall_status = "healthy" if redis_health["status"] == "healthy" else "degraded"

    return jsonify({
        "service": config.SERVICE_NAME,
        "status": overall_status,
        "timestamp": datetime.utcnow().isoformat(),
        "dependencies": {
            "redis_cluster": redis_health,
        }
    }), 200 if overall_status == "healthy" else 503


# ---------- Session Endpoints ----------

@app.route("/sessions", methods=["POST"])
@require_service_auth
@rate_limit
def create_session():
    """Create a new session for a user."""
    data = request.get_json()
    if not data or "user_id" not in data:
        return jsonify({"error": "user_id is required"}), 400

    user_id = data["user_id"]
    metadata = {
        "ip_address": request.headers.get("X-Forwarded-For", request.remote_addr),
        "user_agent": request.headers.get("User-Agent", ""),
    }

    try:
        raw_token = cache_service.create_session(user_id, metadata)
        return jsonify({
            "session_token": raw_token,
            "expires_in": config.SESSION_TOKEN_TTL,
            "token_type": "Bearer",
        }), 201
    except RedisError:
        return jsonify({"error": "Failed to create session"}), 503


@app.route("/sessions/validate", methods=["POST"])
@require_service_auth
@rate_limit
def validate_session():
    """Validate a session token."""
    data = request.get_json()
    if not data or "session_token" not in data:
        return jsonify({"error": "session_token is required"}), 400

    try:
        session_data = cache_service.validate_session(data["session_token"])
        if session_data:
            return jsonify({
                "valid": True,
                "session": session_data,
            }), 200
        else:
            return jsonify({
                "valid": False,
                "session": None,
            }), 401
    except RedisError:
        return jsonify({"error": "Failed to validate session"}), 503


