# ---------- Refresh Token Endpoints ----------

@app.route("/refresh-tokens", methods=["POST"])
@require_service_auth
@rate_limit
def create_refresh_token():
    """Create a refresh token linked to a session."""
    data = request.get_json()
    if not data or "user_id" not in data or "session_token" not in data:
        return jsonify({"error": "user_id and session_token are required"}), 400

    session_token_hash = protector.hash_token(data["session_token"])

    try:
        raw_refresh_token = cache_service.store_refresh_token(
            data["user_id"],
            session_token_hash,
        )
        return jsonify({
            "refresh_token": raw_refresh_token,
            "expires_in": config.REFRESH_TOKEN_TTL,
        }), 201
    except RedisError:
        return jsonify({"error": "Failed to create refresh token"}), 503


@app.route("/refresh-tokens/use", methods=["POST"])
@require_service_auth
@rate_limit
def use_refresh_token():
    """Use a refresh token to get a new session."""
    data = request.get_json()
    if not data or "refresh_token" not in data:
        return jsonify({"error": "refresh_token is required"}), 400

    try:
        token_data = cache_service.use_refresh_token(data["refresh_token"])
        if not token_data:
            return jsonify({
                "valid": False,
                "error": "Invalid or expired refresh token",
            }), 401

        # Create new session
        user_id = token_data["user_id"]
        metadata = {
            "ip_address": request.headers.get("X-Forwarded-For", request.remote_addr),
            "user_agent": request.headers.get("User-Agent", ""),
        }
        new_session_token = cache_service.create_session(user_id, metadata)

        # Create new refresh token
        new_session_hash = protector.hash_token(new_session_token)
        new_refresh_token = cache_service.store_refresh_token(user_id, new_session_hash)

        return jsonify({
            "valid": True,
            "session_token": new_session_token,
            "refresh_token": new_refresh_token,
            "session_expires_in": config.SESSION_TOKEN_TTL,
            "refresh_expires_in": config.REFRESH_TOKEN_TTL,
        }), 200
    except RedisError:
        return jsonify({"error": "Failed to refresh session"}), 503


